#!/usr/bin/env python3
# gen_batch533.py — batches 533-535 (articles 2668-2682)
import os, re, json

BASE = os.path.dirname(__file__)

CSS = "*{box-sizing:border-box;margin:0;padding:0}body{font-family:sans-serif;color:#222;background:#fff}a{color:#0057b8;text-decoration:none}.nav{background:#0057b8;padding:12px 20px;display:flex;align-items:center;justify-content:space-between}.nav a{color:#fff;font-weight:600;font-size:15px}.hero{background:#f0f6ff;padding:48px 20px 36px;text-align:center}h1{font-size:2rem;color:#003d80;margin-bottom:16px}.lead{font-size:1.1rem;color:#444;max-width:640px;margin:0 auto 24px}.cta-btn{background:#ff6600;color:#fff;padding:14px 32px;border-radius:6px;font-size:1rem;font-weight:700;display:inline-block}.content{max-width:760px;margin:36px auto;padding:0 20px}h2{font-size:1.3rem;color:#003d80;margin:28px 0 10px}p{line-height:1.7;color:#333;margin-bottom:14px}.faq{max-width:760px;margin:36px auto;padding:0 20px}.faq h2{font-size:1.4rem;color:#003d80;margin-bottom:18px}details{border:1px solid #dde;border-radius:6px;margin-bottom:10px;padding:12px 16px}summary{font-weight:600;cursor:pointer;color:#003d80}details p{margin-top:8px;color:#444}.cta-box{background:#f0f6ff;border:2px solid #0057b8;border-radius:10px;padding:32px;text-align:center;max-width:640px;margin:40px auto}.cta-box h2{color:#003d80;margin-bottom:12px}.cta-box p{color:#444;margin-bottom:20px}.related{max-width:760px;margin:36px auto;padding:0 20px}.related h2{font-size:1.2rem;color:#003d80;margin-bottom:12px}.related ul{list-style:none}.related li{margin-bottom:8px}.related a{color:#0057b8}footer{background:#003d80;color:#cce;text-align:center;padding:20px;margin-top:48px;font-size:13px}@media(max-width:640px){h1{font-size:1.4rem}.cta-btn{padding:12px 22px}}"

PIXEL = "4520253334926563"

def art(slug, title, desc, tag, tc, h1, lead, secs, faqs, rel):
    out = os.path.join(BASE, "blog", slug)
    os.makedirs(out, exist_ok=True)
    fpath = os.path.join(out, "index.html")
    ld_article = {"@type": "Article", "headline": title, "description": desc,
                  "author": {"@type": "Organization", "name": "ProdutoVivo"},
                  "publisher": {"@type": "Organization", "name": "ProdutoVivo", "url": "https://produtovivo.com.br"}}
    ld_faq = {"@type": "FAQPage", "mainEntity": [
        {"@type": "Question", "name": q, "acceptedAnswer": {"@type": "Answer", "text": a}}
        for q, a in faqs]}
    ld = json.dumps({"@context": "https://schema.org", "@graph": [ld_article, ld_faq]}, ensure_ascii=False)
    secs_html = "".join(f"<h2>{s['h']}</h2><p>{s['p']}</p>" for s in secs)
    faqs_html = "".join(f"<details><summary>{q}</summary><p>{a}</p></details>" for q, a in faqs)
    rel_html = "".join(f'<li><a href="/blog/{r}/">{r.replace("-", " ").title()}</a></li>' for r in rel)
    url = f"https://produtovivo.com.br/blog/{slug}/"
    html = (f'<!DOCTYPE html><html lang="pt-BR"><head>'
            f'<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">'
            f'<title>{title} | ProdutoVivo</title>'
            f'<meta name="description" content="{desc}">'
            f'<meta property="og:title" content="{title}">'
            f'<meta property="og:description" content="{desc}">'
            f'<meta property="og:url" content="{url}">'
            f'<link rel="canonical" href="{url}">'
            f'<script type="application/ld+json">{ld}</script>'
            f'<style>{CSS}</style></head><body>'
            f'<script>!function(f,b,e,v,n,t,s){{if(f.fbq)return;n=f.fbq=function(){{n.callMethod?n.callMethod.apply(n,arguments):n.queue.push(arguments)}};if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version=\'2.0\';n.queue=[];t=b.createElement(e);t.async=!0;t.src=v;s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)}}(window,document,\'script\',\'https://connect.facebook.net/en_US/fbevents.js\');fbq(\'init\',\'{PIXEL}\');fbq(\'track\',\'PageView\');</script>'
            f'<nav class="nav"><a href="/">ProdutoVivo</a><a href="/blog/">Blog</a>'
            f'<a href="/#comprar" class="cta-btn" style="padding:8px 18px;font-size:14px">Quero o Guia</a></nav>'
            f'<div class="hero"><h1>{h1}</h1><p class="lead">{lead}</p>'
            f'<a href="/#comprar" class="cta-btn">Quero o Guia por R$37</a></div>'
            f'<div class="content">{secs_html}</div>'
            f'<section class="cta-box"><h2>Transforme seu conhecimento em receita</h2>'
            f'<p>O guia ProdutoVivo mostra como criar um infoproduto lucrativo com IA — mesmo começando do zero.</p>'
            f'<a href="/#comprar" class="cta-btn">Quero o Guia por R$37</a></section>'
            f'<section class="faq"><h2>Perguntas Frequentes</h2>{faqs_html}</section>'
            f'<div class="related"><h2>Artigos Relacionados</h2><ul>{rel_html}</ul></div>'
            f'<footer><p>&copy; 2025 ProdutoVivo — '
            f'<a href="/privacidade.html" style="color:#cce">Privacidade</a> · '
            f'<a href="/termos.html" style="color:#cce">Termos</a></p></footer>'
            f'</body></html>')
    with open(fpath, "w", encoding="utf-8") as f:
        f.write(html)
    print(f"  OK {slug}")

print("BATCH 533")
art("como-criar-infoproduto-sobre-gestao-de-clinicas-de-dermatologia-adulto",
    "Como Criar Infoproduto sobre Gestão de Clínica de Dermatologia de Adultos",
    "Aprenda a criar infoproduto ensinando dermatologistas a estruturar clínica de dermatologia de adultos de alto padrão, montar portfólio de procedimentos estéticos e crescer com pacientes de prevenção e tratamento.",
    "Gestão de Negócios", "gestao de clinicas de dermatologia adulto",
    "Como Criar Infoproduto sobre Gestão de Clínica de Dermatologia de Adultos",
    "Crie um infoproduto ensinando dermatologistas a montar clínica lucrativa de dermatologia de adultos com procedimentos de alto valor, rastreamento de câncer de pele e modelo de consulta de referência.",
    [{"h": "Dermatologia de Adultos: Alta Demanda com Estética, Câncer de Pele e Acne como Principais Portas de Entrada", "p": "Dermatologia de adultos — especialidade que diagnostica e trata condições da pele, cabelo e unhas em adultos, incluindo câncer de pele (melanoma — 8.400 casos novos/ano no Brasil; carcinoma basocelular — CBC — o mais comum, com 185.000 casos/ano; carcinoma espinocelular — CEC — com 82.000 casos/ano; diagnóstico com dermatoscopia e excisão cirúrgica), acne adulta (afeta 25 a 35% das mulheres e 12% dos homens acima de 25 anos; tratamento com isotretinoína oral, antibióticos tópicos, ácido azelaico, e luz e laser), melasma (afeta 30 a 40% das mulheres brasileiras acima de 30 anos; tratamento combinado com fotoproteção rigorosa, clareadores tópicos — ácido kójico, tranexâmico, vitamina C — e peelings químicos), psoríase (prevalência de 2 a 3% da população; biológicos — secukinumabe, ixekizumabe, risankizumabe — para psoríase moderada a grave), e procedimentos estéticos (toxina botulínica, preenchedores de ácido hialurônico, laser CO2, peelings médios e profundos) — tem demanda crescente de adultos de 25 a 55 anos que buscam tanto cuidado terapêutico quanto estético. Dermatologista que tem portfólio equilibrado entre clínica (diagnóstico e tratamento de doenças) e estética (procedimentos de rejuvenescimento e de harmonização) tem modelo de maior rentabilidade e de maior diversificação de receita."},
     {"h": "Procedimentos Estéticos: O Produto de Maior Ticket e de Maior Recorrência em Dermatologia Privada", "p": "Procedimentos estéticos em dermatologia — toxina botulínica (R$800 a R$2.500 por sessão; recorrência de 4 em 4 meses), preenchedores de ácido hialurônico (R$1.200 a R$4.000 por seringa; recorrência de 12 a 18 meses), laser fracionado (R$600 a R$1.800 por sessão; protocolo de 3 a 6 sessões), peelings químicos (R$350 a R$900 por sessão; protocolo mensal na fase de tratamento), e bioestimuladores de colágeno (Radiesse, Sculptra, Ellansé — R$1.500 a R$4.000 por sessão; recorrência de 12 a 24 meses) — têm ticket médio muito superior ao da consulta dermatológica convencional (R$200 a R$500) e geram recorrência programada que a consulta de doença não gera. Dermatologista com 3 sessões de botox por semana (10 pacientes × R$1.200 médio) tem R$12.000/semana de receita de procedimento estético — sem depender de plano de saúde, sem fila de espera, e com horários que o próprio médico define. Clínica de dermatologia que integra consulta + procedimento tem conversão de 40 a 60% de pacientes terapêuticos para procedimentos estéticos — especialmente em acne (pós-tratamento com peeling e laser), melasma (tratamento + fotoproteção + procedimento), e rastreamento de câncer de pele (paciente que retorna anualmente para mapeamento fica exposto ao portfólio estético)."},
     {"h": "Rastreamento de Câncer de Pele: O Serviço de Maior Recorrência e de Maior Impacto Clínico em Dermatologia", "p": "Rastreamento de câncer de pele — mapeamento corporal total com dermatoscopia digital (FotoFinder, Molemax, VisioMed — análise computadorizada de todos os nevos com comparação evolutiva semestral ou anual) — é o produto de maior recorrência em dermatologia: paciente com fototipo I ou II (pele clara), histórico familiar de melanoma, ou uso de imunossupressor retorna anualmente para o mapeamento. Dermatologista que tem dermatoscopia digital com câmera de corpo inteiro (custo de R$80.000 a R$250.000) tem produto de rastreamento diferenciado que o dermatologista com dermatoscópio manual não tem — e que o paciente de alto risco percebe imediatamente como superior. Paciente que faz o primeiro mapeamento digital e tem 47 nevos fotografados sabe que precisa voltar todo ano para comparação — e não troca de dermatologista porque o histórico fica na clínica. Mapeamento com 10 pacientes/semana a R$600 a R$1.200 por mapeamento = R$6.000 a R$12.000/semana de receita recorrente anual de baixo custo operacional."},
     {"h": "Infoproduto para Gestão de Clínica de Dermatologia de Adultos", "p": "Cursos de gestão para clínicas de dermatologia de adultos podem ser precificados entre R$1.497 e R$2.997. O público são dermatologistas que trabalham em hospitais e convênios e que querem estruturar clínica particular de alto valor, residentes de dermatologia planejando carreira privada com foco em estética médica e procedimentos de alto ticket, e dermatologistas de carreira que querem expandir o portfólio de procedimentos estéticos sem abrir mão da dermatologia clínica."}],
    [("Como dermatologista pode captar adultos que nunca fizeram rastreamento de câncer de pele?", "Adulto de 40 anos que passou a infância na praia, que nunca fez dermatoscopia, e que tem nevo que mudou de cor recentemente sabe que deveria ir ao dermatologista mas não foi porque 'está com aspecto normal'. Dermatologista que quer captar esses adultos: conteúdo no Instagram sobre 'os 5 sinais de que um nevo merece avaliação urgente — e como o ABCDE do melanoma se aplica à sua pele', campanha de Dezembro Laranja (mês de conscientização de câncer de pele — 3° trimestre é o período de maior exposição solar no Sul/Sudeste), e parceria com academias e clubes de natação para triagem de rastreamento. Adulto que descobre nevo suspeito que o dermatologista avalia e retira com biópsia positiva para CBC se torna paciente fiel de rastreamento anual — e indica todos os familiares com fototipos semelhantes."),
     ("Como dermatologista pode usar a acne adulta como porta de entrada para o portfólio estético?", "Paciente adulta de 28 a 38 anos que trata acne moderada com dermatologista tem interesse natural em procedimentos de pós-acne: cicatrizes atróficas (laser fracionado ablativo ou não ablativo — custo de R$800 a R$1.800 por sessão, protocolo de 4 a 6 sessões), manchas pós-inflamatórias (peelings químicos de ATA a 20 a 30% ou de ácido mandélico — custo de R$350 a R$700 por sessão), e manutenção da pele (peelings de manutenção mensais, cosméticos médicos prescritos). Dermatologista que apresenta o roadmap de tratamento logo na 2ª consulta — 'após controlar a acne ativa em 3 meses, podemos tratar as sequelas com laser fracionado — custo total de R$5.000 a R$9.000 em 6 meses' — tem conversão de 60 a 70% de paciente terapêutico para procedimento estético, porque a paciente já confia no médico e já quer o resultado que o médico mostrou."),
     ("Vale o dermatologista criar conteúdo sobre fotoproteção para adultos que subestimam o risco do sol?", "Sim — adulto que não usa protetor solar diariamente pesquisa 'protetor solar é realmente necessário no dia a dia', 'qual FPS protege contra melanoma', e 'como o sol envelhece a pele'. Dermatologista que cria conteúdo: 'o que acontece com a pele quando você ignora o protetor solar por 10 anos — e o que ainda dá para reverter', 'como escolher o protetor solar certo para a sua pele (oleosa, seca, com melasma, com acne)', e 'o protetor solar que eu uso e que indico — e por que o FPS 30 não é suficiente no Brasil'. Conteúdo de fotoproteção tem alto alcance em mulheres de 25 a 45 anos — o público de maior demanda por dermatologia estética e de maior engajamento com saúde preventiva. Dermatologista com posicionamento de especialista em fotoproteção tem captação de pacientes que chegam com o produto já indicado — e que ficam para o rastreamento e o procedimento estético.")],
    ["como-criar-infoproduto-sobre-marketing-para-profissionais-de-dermatologia-pediatrica",
     "como-criar-infoproduto-sobre-gestao-de-clinicas-de-mastologia",
     "como-criar-infoproduto-sobre-gestao-de-clinicas-de-medicina-esportiva"])
art("como-criar-infoproduto-sobre-marketing-para-profissionais-de-nefrologia-clinica",
    "Como Criar Infoproduto sobre Marketing para Nefrologistas Clínicos",
    "Aprenda a criar infoproduto ensinando nefrologistas a captar pacientes de doença renal crônica, hipertensão renovascular e transplante renal e construir consultório de referência em nefrologia clínica.",
    "Marketing para Profissionais", "marketing para profissionais de nefrologia clinica",
    "Como Criar Infoproduto sobre Marketing para Nefrologistas Clínicos",
    "Crie um infoproduto ensinando nefrologistas a posicionar expertise em DRC, captar encaminhamentos de clínicos e endocrinologistas e construir consultório de referência em nefrologia clínica.",
    [{"h": "Nefrologia Clínica: Alta Demanda com DRC como Epidemia Silenciosa e Principal Fonte de Encaminhamento", "p": "Nefrologia clínica — especialidade que diagnostica e trata doenças dos rins, incluindo doença renal crônica (DRC — afeta 10 a 15% da população adulta brasileira; 75% dos casos são consequência de HAS e DM2 não controlados; estadiamento com TFG — Taxa de Filtração Glomerular — de G1 a G5, com G5 correspondendo à necessidade de terapia renal substitutiva — diálise ou transplante), glomerulonefrites (nefropatia por IgA, nefropatia membranosa, síndrome nefrótica — diagnóstico com biópsia renal), hipertensão renovascular (estenose de artéria renal — triagem com Doppler de artérias renais), litíase renal (cálculo renal de repetição — investigação metabólica: oxalúria, citratúria, cálcio urinário, ácido úrico urinário), e acompanhamento de transplantados renais (imunossupressão, monitoramento de função do enxerto, profilaxia de infecções oportunistas) — tem demanda crescente de encaminhamentos de clínicos gerais, endocrinologistas (que acompanham DM2), e cardiologistas (que acompanham HAS) que identificam queda de TFG em exames de rotina."},
     {"h": "DRC Pré-Diálise: O Nicho de Maior Volume e de Maior Impacto Preventivo em Nefrologia", "p": "DRC pré-diálise — estágios G1 a G4, com TFG entre 15 e 90 mL/min/1,73m² — é o nicho de maior volume em nefrologia clínica: 90 a 95% dos pacientes de nefrologia em acompanhamento ambulatorial estão em fase pré-diálise. Nefrologista que tem protocolo de consulta de DRC estruturado — com revisão da causa base e controle rigoroso dos fatores progressores (PA < 130/80, HbA1c < 7%, proteinúria < 0,5g/dia com inibidor de SRAA — iECA ou BRA + SGLT2 inibidor desde o lançamento do dapagliflozina para DRC G2-4 com proteinúria, aprovado pelo FDA em 2021 e pela Anvisa em 2023), avaliação de complicações da DRC (anemia — EPO e ferro IV; hiperparatireoidismo secundário — calcitriol ou análogos de vitamina D; acidose metabólica — bicarbonato oral), e planejamento de acesso vascular precoce (fístula arteriovenosa quando TFG < 20-25 mL/min) — tem produto de cuidado longitudinal de alta complexidade que o clínico geral ou o cardiologista que acompanha o paciente não tem condições de oferecer."},
     {"h": "Hemodiálise e Transplante: Como o Nefrologista Constrói Rede de Referência de Alto Valor", "p": "Nefrologista que tem contrato de médico nefrologista de clínica de hemodiálise (clínica satélite de diálise — remuneração de R$8.000 a R$20.000/mês por contrato de médico responsável técnico + visitas semanais a cada paciente em HD, com carteira de 50 a 120 pacientes em diálise por clínica) tem modelo de renda complementar ao consultório que não depende de plano de saúde ou de consulta particular. Nefrologista com 1 a 2 contratos de clínica de hemodiálise tem R$16.000 a R$40.000/mês de renda recorrente contratual — além do consultório. Para transplante renal, nefrologista que tem convênio com hospital transplantador e que encaminha seus pacientes com TFG < 15 mL/min para avaliação de transplante (lista de espera do SUS — 5 a 8 anos; transplante intervivo com doador relacionado — menor espera) tem posicionamento de 'nefrologista que cuida do paciente do início ao transplante' que o paciente com DRC avançada percebe imediatamente como de maior valor."},
     {"h": "Infoproduto para Marketing em Nefrologia Clínica", "p": "Cursos de marketing para nefrologistas clínicos podem ser precificados entre R$1.497 e R$2.997. O público são nefrologistas que trabalham em hospitais e clínicas de hemodiálise e que querem estruturar consultório particular de referência, residentes de nefrologia planejando carreira com foco em DRC pré-diálise ou em transplante renal, e clínicos gerais com interesse em nefrologia que atendem muitos pacientes com HAS e DM2 e que querem aprofundar o manejo de DRC estágios iniciais."}],
    [("Como nefrologista pode captar pacientes de DRC que não sabem que têm a doença?", "Paciente com HAS há 10 anos e DM2 há 5 anos que faz creatinina anual mas que nenhum médico calculou a TFG para interpretar o estágio da DRC muito provavelmente está no estágio G2 ou G3 sem diagnóstico de DRC estabelecido — e sem encaminhamento para nefrologista. Nefrologista que quer captar esses pacientes: conteúdo para clínicos gerais e endocrinologistas com protocolo de 'quando encaminhar para nefrologia' (TFG < 60 mL/min por mais de 3 meses, ou proteinúria > 300 mg/g, ou queda de TFG > 5 mL/min/ano), calculadora online de TFG (CKD-EPI) com botão 'se seu resultado estiver abaixo de 60, consulte um nefrologista', e conteúdo no Instagram sobre 'diabético ou hipertenso? Saiba como calcular se seus rins estão funcionando bem com 2 exames que você provavelmente já tem'. Paciente que descobre TFG=42 mL/min (G3b) e que nunca havia tido o diagnóstico de DRC tem urgência imediata de iniciar acompanhamento com nefrologista — e não demora para marcar."),
     ("Como nefrologista pode usar o SGLT2 inibidor como diferencial de prescrição para pacientes com DRC e DM2?", "SGLT2 inibidor (dapagliflozina — Farxiga, aprovado para DRC com TFG 25 a 75 mL/min e proteinúria > 200 mg/g; empagliflozina — Jardiance, aprovado para DRC com TFG > 20 mL/min em diabéticos) tem evidência de redução de 39 a 44% na progressão de DRC e de 31 a 40% no risco de hospitalização por insuficiência cardíaca — tornando-se o maior avanço terapêutico em nefrologia da última década. Nefrologista que tem protocolo de indicação e acompanhamento de SGLT2 inibidor em DRC — com monitoramento de TFG, potássio, e risco de cetoacidose euglicêmica — tem diferencial de prescrição que muitos clínicos gerais ainda não incorporaram por insegurança com a redução transitória de TFG no início (dip de creatinina de 2 a 4 semanas). Paciente que inicia dapagliflozina com nefrologista e que é informado sobre o dip esperado de TFG e sobre os benefícios a longo prazo tem adesão muito maior do que o paciente que interrompe o medicamento com o clínico porque se assustou com 'os rins pioraram'."),
     ("Vale o nefrologista criar conteúdo sobre prevenção de DRC para pacientes com HAS e DM2?", "Sim — paciente com HAS ou DM2 pesquisa 'o que HAS faz com os rins', 'como saber se meus rins estão funcionando bem', e 'creatinina alta — o que significa'. Nefrologista que cria conteúdo: 'hipertensão e diabetes podem destruir seus rins sem dar sintoma — saiba como monitorar', 'creatinina alta — quando é sinal de alarme e quando é variação normal', e 'o que comer e o que evitar para proteger os rins se você tem pressão alta ou diabetes'. Conteúdo que traduz risco renal em ação preventiva tem captação de pacientes que chegam à consulta de nefrologia antes de precisar de diálise — o melhor momento para intervenção preventiva. Nefrologista com posicionamento de especialista em prevenção de DRC tem diferencial de 'nefrologista que cuida de você antes de precisar de diálise' que o paciente com HAS e DM2 que tem medo de diálise valoriza imediatamente.")],
    ["como-criar-infoproduto-sobre-marketing-para-profissionais-de-medicina-de-familia",
     "como-criar-infoproduto-sobre-marketing-para-profissionais-de-endocrinologia-adulto",
     "como-criar-infoproduto-sobre-marketing-para-profissionais-de-cardiologia-preventiva"])
art("como-criar-infoproduto-sobre-vendas-para-o-setor-de-consultoria-de-marketing",
    "Como Criar Infoproduto sobre Vendas para o Setor de Consultoria de Marketing",
    "Aprenda a criar infoproduto ensinando consultores de marketing a vender projetos de estratégia e execução de marketing para PMEs com processo comercial de diagnóstico, proposta de valor e ROI calculado.",
    "Vendas por Setor", "vendas para o setor de consultoria de marketing",
    "Como Criar Infoproduto sobre Vendas para o Setor de Consultoria de Marketing",
    "Crie um infoproduto ensinando consultores de marketing a fechar contratos com PMEs usando diagnóstico de presença digital, proposta de valor diferenciada e processo comercial de ROI de marketing.",
    [{"h": "Consultoria de Marketing: Mercado Fragmentado com PMEs Sem Estratégia como Principal Oportunidade", "p": "Consultoria de marketing — serviço que diagnosa a situação atual de marketing de uma empresa, define estratégia de posicionamento e canais, cria e executa o plano de marketing, e mede os resultados — tem mercado de R$8B no Brasil com crescimento de 18% ao ano e com PMEs de 10 a 200 funcionários que têm orçamento de marketing mas que não têm estratégia como principal oportunidade. PME que publica nas redes sociais sem estratégia de persona, que investe em tráfego pago sem acompanhar ROAS, e que não tem processo de geração de leads estruturado está deixando dinheiro na mesa — e reconhece esse problema quando perde clientes para concorrentes que 'aparecem mais'. Consultor de marketing que consegue mostrar no diagnóstico o custo de oportunidade da falta de estratégia — 'você está investindo R$3.000/mês em tráfego pago com ROAS de 1,2x quando a média do setor é 3,5x — você está perdendo R$7.000/mês em receita que poderia estar capturando' — tem argumento de entrada irresistível para o dono de PME que vê o número."},
     {"h": "Modelo de Proposta: Como o Consultor de Marketing Fecha Contratos de R$5.000 a R$20.000/mês", "p": "Consultoria de marketing tem 3 modelos de contrato típicos: 1) diagnóstico de marketing (escopo fechado — 30 a 45 dias — entrevistas com time, análise de canais, benchmarking de concorrentes, entrega de plano de marketing com prioridades — R$5.000 a R$15.000; produto de entrada que financia o contrato recorrente), 2) retainer mensal de estratégia (6 a 12 meses — 1 reunião semanal, revisão de campanhas, gestão de agência ou de freelas de execução, relatório mensal de KPIs — R$5.000 a R$15.000/mês dependendo do porte da empresa), e 3) contrato de performance (fee fixo baixo + bônus por resultado — ex: R$2.000/mês fixo + 3% da receita incrementada acima do baseline — modelo que alinha incentivos e que fecha com decisores que têm aversão a fee fixo alto sem garantia de resultado). Consultor que apresenta a proposta com ROI projetado específico para o setor do prospect — 'para empresa de serviços B2B do seu tamanho, a estratégia de content + SEO + LinkedIn que vou implementar gera em média 8 a 12 leads qualificados/mês em 6 meses — no seu ticket médio de R$15.000, são R$120.000 a R$180.000 de receita nova com fee de R$8.000/mês' — fecha muito mais do que o consultor que apresenta lista de entregáveis."},
     {"h": "Nicho Vertical: Por Que o Consultor de Marketing que Especializa em Setor Cobra 3x Mais e Fecha Mais Rápido", "p": "Consultor de marketing generalista — que atende restaurante, escritório de contabilidade, e loja de móveis ao mesmo tempo — tem dificuldade de precificação premium porque o cliente não percebe especialização. Consultor que especializa em setor vertical (consultoria de marketing exclusivamente para clínicas médicas, ou para construtoras de médio porte, ou para SaaS B2B) tem: 1) cases comparáveis ('já fiz isso para 3 clínicas de ortopedia — resultado médio de 40 consultas novas/mês em 6 meses'), 2) linguagem do setor (sabe o que é CPC médio em Google Ads para palavras de saúde, sabe o ROAS esperado de campanha para varejo de construção), e 3) playbook reutilizável (os mesmos canais, as mesmas estratégias de conteúdo, e os mesmos benchmarks funcionam para todos os clientes do mesmo setor — custo de entrega muito menor). Especialista em marketing para clínicas médicas cobra R$12.000/mês vs. R$5.000/mês do generalista — e fecha mais rápido porque o cliente percebe que o consultor já resolveu o problema exato que ele tem."},
     {"h": "Infoproduto para Vendas no Setor de Consultoria de Marketing", "p": "Cursos de vendas para o setor de consultoria de marketing podem ser precificados entre R$1.497 e R$2.997. O público são consultores de marketing e profissionais de marketing digital que querem estruturar consultoria própria e sair do modelo de freela por projeto, gerentes de marketing de empresas que querem montar negócio próprio de consultoria com a carteira que já têm, e donos de agência de marketing que querem adicionar consultoria estratégica ao portfólio de serviços."}],
    [("Como consultor de marketing pode fechar o primeiro contrato de retainer sem ter case de sucesso documentado?", "Consultor de marketing sem case documentado tem 3 estratégias para fechar o primeiro retainer: 1) diagnóstico gratuito ou simbólico (R$500 a R$1.500) para empresa de 20 a 50 funcionários do setor que quer especializar — 'faço o diagnóstico de marketing da sua empresa gratuitamente; se a entrega for boa, posso te propor o retainer de implementação'; 2) piloto de 90 dias com fee reduzido (60 a 70% do fee cheio) e meta clara ('se eu não atingir X leads no 1° trimestre, você pode encerrar sem multa') — reduz a percepção de risco do decisor que tem receio de comprometer budget sem resultado garantido; e 3) prospecção cirúrgica por conexão de 1° grau no LinkedIn — ligar para antigos colegas de trabalho, ex-clientes, e contatos próximos com proposta específica: 'sei que você precisa de X — tenho a estratégia e o processo para entregar — posso te mostrar em 30 minutos como funcionaria no seu negócio'. O primeiro contrato é sempre o mais difícil; os seguintes são referendados pelo resultado do anterior."),
     ("Como consultor de marketing pode usar o diagnóstico de marketing como produto de entrada para contratos maiores?", "Diagnóstico de marketing — entregável de 30 a 45 páginas que mapa o posicionamento atual da empresa (persona, proposta de valor, análise de concorrentes), avalia os canais digitais (SEO, redes sociais, tráfego pago, email marketing) com métricas comparadas ao benchmark do setor, e prioriza as 3 a 5 ações de maior impacto para os próximos 6 meses — é o produto de entrada ideal para consultoria de marketing por 3 razões: 1) é tangível (o cliente vê o que está comprando antes de comprometer budget recorrente), 2) tem preço de entrada acessível (R$5.000 a R$15.000 para PME vs. R$60.000 a R$120.000 de retainer anual), e 3) cria o contexto para a proposta de implementação. Consultor que entrega diagnóstico de qualidade — com dados reais do Google Analytics, do Meta Ads Manager, e do Google Search Console, com benchmarks do setor, e com roadmap de 90 dias priorizado — converte 70 a 80% dos clientes de diagnóstico para retainer de implementação."),
     ("Vale o consultor de marketing criar conteúdo sobre erros de marketing de PME para atrair decisores?", "Sim — dono de PME que investe em marketing sem ver resultado pesquisa 'por que meu marketing não funciona', 'como saber se estou gastando certo em tráfego pago', e 'como gerar leads qualificados com pouco orçamento'. Consultor que cria conteúdo: '5 erros de marketing que custam R$3.000/mês a PMEs que acham que estão investindo certo', 'como calcular se o seu investimento em tráfego pago está dando retorno real (o cálculo que 80% dos donos de PME nunca fizeram)', e 'o diagnóstico de marketing que eu faço nos primeiros 30 minutos com qualquer PME'. Conteúdo que mostra competência específica para o problema que o decisor já tem — sem jargão de agência — tem captação de donos que chegam à reunião de diagnóstico dizendo 'você descreveu exatamente o que está acontecendo comigo'.")],
    ["como-criar-infoproduto-sobre-gestao-de-negocios-de-empresa-de-consultoria-de-marketing-digital",
     "como-criar-infoproduto-sobre-vendas-para-o-setor-de-consultoria-de-gestao-de-mudancas",
     "como-criar-infoproduto-sobre-gestao-de-negocios-de-empresa-de-consultoria-de-vendas"])
art("como-criar-infoproduto-sobre-gestao-de-negocios-de-empresa-de-consultoria-de-experiencia-do-cliente",
    "Como Criar Infoproduto sobre Gestão de Empresa de Consultoria de Experiência do Cliente",
    "Aprenda a criar infoproduto ensinando consultores de CX a estruturar empresa de consultoria de experiência do cliente, conquistar contratos com empresas de médio e grande porte e escalar com projetos de NPS e jornada.",
    "Gestão de Negócios", "gestao de negocios de empresa de consultoria de experiencia do cliente",
    "Como Criar Infoproduto sobre Gestão de Empresa de Consultoria de Experiência do Cliente",
    "Crie um infoproduto ensinando consultores de CX a estruturar empresa de consultoria de experiência do cliente, posicionar expertise em NPS e jornada do cliente e conquistar contratos com empresas de varejo, saúde e serviços.",
    [{"h": "Consultoria de CX: Mercado em Expansão com Empresas de Alto Churn como Principal Oportunidade", "p": "Consultoria de experiência do cliente (CX — Customer Experience) — especialidade que diagnostica e melhora a percepção do cliente em todos os pontos de contato com a empresa, desde a descoberta até o pós-venda, usando metodologias de jornada do cliente (Customer Journey Mapping), voz do cliente (VoC — Voice of Customer), NPS (Net Promoter Score — metodologia Bain & Company para medir lealdade: Promotores minus Detratores), CES (Customer Effort Score — mede facilidade de interação), e CSAT (Customer Satisfaction Score — satisfação pontual por transação) — tem demanda crescente no Brasil com o aumento de empresas que perceberam que churn alto e NPS negativo custam mais do que o investimento em melhoria de CX. Empresa que tem NPS abaixo de 20 (zona de alerta — indústria de telecomunicações tem NPS médio de 20; varejo de moda tem NPS médio de 45; serviços de saúde têm NPS médio de 50 a 70) e que tem custo de aquisição de cliente (CAC) crescendo enquanto o lifetime value (LTV) cai está em ciclo vicioso de churn que só consultoria de CX resolve de forma sistêmica."},
     {"h": "Modelo de Negócio: Como Precificar Projetos de CX de R$30.000 a R$300.000", "p": "Consultoria de CX tem 3 modelos de projeto típicos: 1) diagnóstico de CX (escopo de 60 a 90 dias — mapeamento da jornada do cliente atual com pesquisa de VoC em 200 a 500 clientes, análise de NPS por touchpoint, identificação dos 3 a 5 momentos de maior impacto negativo na jornada — R$30.000 a R$80.000; produto de entrada que financia a implementação), 2) projeto de transformação de CX (6 a 12 meses — redesenho dos processos de maior impacto, treinamento de equipe, implementação de métricas, acompanhamento de NPS — R$80.000 a R$300.000), e 3) programa de governança de CX (retainer mensal — 12 a 24 meses — para empresas que querem CX como competência permanente: comitê de CX, revisão trimestral de jornada, benchmarking de NPS, relatório mensal de VoC — R$15.000 a R$40.000/mês). Consultor que posiciona o ROI do projeto de CX — 'reduzir o churn de 4% para 3% em empresa com 10.000 clientes a R$200/mês representa R$2.400.000/ano de receita preservada — o projeto de R$150.000 se paga em 3 semanas de churn evitado' — fecha budget com CFO que o consultor que vende 'melhoria da experiência do cliente' sem número não fecha."},
     {"h": "NPS por Touchpoint: A Ferramenta que Diferencia o Consultor de CX que Gera Resultado", "p": "NPS transacional por touchpoint — medição do NPS após cada interação específica da jornada (NPS pós-compra, NPS pós-atendimento de SAC, NPS pós-onboarding, NPS pós-renovação) em vez do NPS relacional anual — é o que diferencia o consultor de CX que encontra o problema real do que entrega relatório de NPS geral sem ação. Consultor que implementa NPS transacional: 1) identifica quais touchpoints têm NPS abaixo do benchmark do setor (atendimento de SAC com NPS 10 vs. benchmark de 40 é o touchpoint a priorizar), 2) correlaciona o NPS do touchpoint com o churn (clientes Detratores no atendimento têm 3x mais churn do que Promotores?), e 3) prioriza a correção do touchpoint de maior impacto de LTV. Empresa que tinha NPS de 28 geral e que, após diagnóstico, descobriu que o problema estava no touchpoint de entrega (NPS de -15) e corrigiu o processo de entrega (de 7 dias para 3 dias) e subiu o NPS para 52 em 6 meses tem case de CX com ROI medido — e que o consultor usa para vender o próximo projeto."},
     {"h": "Infoproduto para Gestão de Empresa de Consultoria de Experiência do Cliente", "p": "Cursos de gestão de empresa de consultoria de CX podem ser precificados entre R$1.497 e R$2.997. O público são profissionais de marketing e de atendimento que querem estruturar consultoria própria de CX, gerentes de customer success e de experiência do cliente de empresas que querem sair do modelo CLT para montar empresa de consultoria com a expertise acumulada, e consultores de gestão e de RH que querem adicionar CX ao portfólio como diferencial de modernidade."}],
    [("Como consultor de CX pode vender diagnóstico de NPS para empresa que nunca mediu NPS?", "Empresa que nunca mediu NPS frequentemente tem percepção de que os clientes estão 'satisfeitos' porque não recebe muita reclamação — mas não sabe o que não sabe. Consultor de CX que quer vender diagnóstico de NPS para essa empresa: abordagem consultiva de entrada ('você sabe qual percentual dos seus clientes atuais indicaria sua empresa para um amigo? Eu posso responder essa pergunta em 30 dias — e mostrar onde estão os clientes que estão pensando em ir para o concorrente'), análise gratuita de reviews públicos (Google Meu Negócio, Reclame Aqui, Trustpilot — 'encontrei 47 reviews negativos em que os clientes reclamam do mesmo problema de atendimento; posso mostrar como isso está impactando seu CAC'), e referência de concorrente direto com NPS alto ('seu concorrente tem NPS de 62 e você não tem NPS medido — como você sabe se está ganhando ou perdendo na percepção do cliente?'). Empresa que vê o dado de reviews negativos do concorrente vs. o próprio fica curiosa sobre o próprio NPS — e o diagnóstico de NPS é o produto de entrada natural."),
     ("Como consultor de CX pode usar o Customer Journey Mapping para mostrar o problema que o cliente sente mas não consegue articular?", "Customer Journey Mapping — mapeamento visual de todas as etapas que o cliente percorre desde a descoberta da empresa até o pós-venda, com emoções, pontos de dor, e oportunidades de melhoria em cada etapa — é a ferramenta mais poderosa para mostrar ao CEO ou ao CMO um problema que eles sabem que existe mas que nunca viram documentado. Consultor que faz o CJM em workshop de 4 a 8 horas com o time multidisciplinar (vendas, marketing, atendimento, produto) usa metodologia de empathy map e de swimming lanes para revelar: 'em média, o cliente que compra pela primeira vez passa por 8 etapas em 3 semanas — e em 4 delas a experiência é categorizada como frustrante pelo próprio time interno'. CEO que vê o mapa e reconhece os pontos de dor que os clientes reclamam (mas que o time interno estava acostumado a normalizar) tem urgência imediata para corrigir — e o projeto de transformação de CX está vendido."),
     ("Vale o consultor de CX criar conteúdo sobre NPS para gestores que nunca usaram a métrica?", "Sim — gestor de empresa de serviços que quer medir satisfação de cliente mas que só conhece pesquisa de satisfação (CSAT de 1 a 5) pesquisa 'o que é NPS e como implementar', 'como calcular NPS da minha empresa', e 'diferença entre NPS CSAT e CES'. Consultor que cria conteúdo: 'NPS — o que é, como calcular em 5 minutos, e por que é a única métrica de satisfação que importa para crescimento', 'os 3 erros que empresas cometem ao implementar NPS pela primeira vez — e como evitar', e 'como eu diagnostiquei um churn de 30% em empresa que achava que os clientes estavam satisfeitos — e como resolvemos em 4 meses'. Conteúdo que ensina NPS com aplicação prática para PMEs (não apenas o conceito teórico) tem captação de gestores que tentam implementar NPS sozinhos, descobrem que é mais complexo do que parece, e buscam o consultor que escreveu o guia que eles leram.")],
    ["como-criar-infoproduto-sobre-gestao-de-negocios-de-empresa-de-consultoria-de-gestao-de-mudancas",
     "como-criar-infoproduto-sobre-gestao-de-negocios-de-empresa-de-consultoria-de-vendas",
     "como-criar-infoproduto-sobre-gestao-de-negocios-de-empresa-de-consultoria-de-marketing-digital"])
art("como-criar-infoproduto-sobre-marketing-para-profissionais-de-cirurgia-geral",
    "Como Criar Infoproduto sobre Marketing para Cirurgiões Gerais",
    "Aprenda a criar infoproduto ensinando cirurgiões gerais a captar pacientes de hérnia, vesícula, apendicite e proctologia e construir consultório de referência em cirurgia geral de alto padrão.",
    "Marketing para Profissionais", "marketing para profissionais de cirurgia geral",
    "Como Criar Infoproduto sobre Marketing para Cirurgiões Gerais",
    "Crie um infoproduto ensinando cirurgiões gerais a posicionar expertise em cirurgia laparoscópica, captar encaminhamentos de clínicos e construir consultório de referência em cirurgia geral minimamente invasiva.",
    [{"h": "Cirurgia Geral: Alta Demanda com Hérnia, Vesícula e Proctologia como Principais Portas de Entrada", "p": "Cirurgia geral — especialidade que opera condições do aparelho digestivo, da parede abdominal, da glândula tireoide, das mamas e de outras estruturas, incluindo herniorrafia (hérnia inguinal — mais de 200.000 operações/ano no Brasil, sendo a cirurgia eletiva mais comum; laparoscópica ou aberta dependendo do tamanho e da localização; tela sintética de polipropileno como padrão), colecistectomia (retirada da vesícula biliar laparoscópica — mais de 150.000 operações/ano; indicada para colelitíase sintomática, colecistite aguda, e coledocolitíase com CPRE prévia), apendicectomia (emergência mais comum em cirurgia geral; laparoscópica com 3 portais tem recuperação em 24 a 48 horas; aberta reservada para caso com peritonite com contaminação extensa), proctologia (hemorroidas — ligadura elástica ambulatorial, cirurgia de Milligan-Morgan ou Parks para grau III e IV; fissura anal — esfincterotomia lateral interna; fístula anal; prolapso retal), e tireoidectomia (nódulo tireoidiano com biópsia positiva ou suspeita, bócio multinodular compressivo, hipertireoidismo refratário) — tem demanda crescente de pacientes que querem cirurgia laparoscópica de curta internação, com alta em 24 horas e retorno ao trabalho em 3 a 5 dias."},
     {"h": "Cirurgia Laparoscópica: O Diferencial que Atrai Pacientes Ativos com Agenda Cheia", "p": "Cirurgia laparoscópica — técnica minimamente invasiva com 3 a 4 portais de 5 a 12mm em vez de incisão abdominal convencional de 8 a 15cm — tem vantagens que os pacientes ativos percebem imediatamente: 1) internação de 12 a 24 horas vs. 3 a 5 dias para cirurgia aberta, 2) retorno ao trabalho em 5 a 7 dias vs. 15 a 30 dias, 3) dor pós-operatória muito menor (EVA médio de 3 vs. 6 nas primeiras 24 horas), e 4) cicatrizes mínimas (3 a 4 pontinhos de 0,5 a 1cm vs. cicatriz mediana ou subcostal de 8 a 15cm). Cirurgião geral que tem expertise em laparoscopia — com pelo menos 200 a 300 colecistectomias e 100 a 150 herniorrafias laparoscópicas como volume mínimo de formação de competência — tem diferencial técnico que o cirurgião que opera principalmente por laparotomia não tem. Paciente de 40 anos que precisa de herniorrafia inguinal e que tem reunião importante em uma semana quer o cirurgião laparoscópico que opera na sexta e libera na segunda — não o que opera na segunda-feira e libera na quinta."},
     {"h": "Proctologia: O Subespecialidade de Maior Tabela e de Maior Diferenciação em Cirurgia Geral", "p": "Proctologia — subespecialidade de cirurgia geral que trata condições do reto, cólon, e canal anal, incluindo hemorroidas (ligadura elástica para grau I e II em consultório — R$400 a R$800 por sessão, sem anestesia; hemorrhoidectomy excisional para grau III e IV em centro cirúrgico — R$3.000 a R$8.000), fissura anal (tratamento conservador com diltiazem 2% tópico e balneoterapia; esfincterotomia lateral interna para fissura crônica), fístula anal (diagnosticada por MRI ou ecoendoscopia transanal; cirurgia de fistulotomia para fístulas simples, técnica de LIFT ou plug para fístulas complexas), e doença inflamatória intestinal (retocolite ulcerativa e Crohn — referência cirúrgica para colectomia quando necessário) — tem diferencial de receita em consultório que a cirurgia geral pura não tem: ligadura elástica de hemorroidas feita em consultório com equipamento de banda elástica (custo de R$3.000 a R$5.000) gera R$400 a R$800 por procedimento ambulatorial de 5 a 10 minutos — sem anestesia, sem centro cirúrgico, sem internação. Cirurgião que faz 5 ligaduras elásticas por semana tem R$2.000 a R$4.000 de receita ambulatorial direta de baixo custo operacional."},
     {"h": "Infoproduto para Marketing em Cirurgia Geral", "p": "Cursos de marketing para cirurgiões gerais podem ser precificados entre R$1.497 e R$2.997. O público são cirurgiões gerais que trabalham em regime de plantão hospitalar e que querem estruturar consultório particular eletivo, residentes de cirurgia geral planejando carreira com foco em laparoscopia avançada ou em proctologia, e cirurgiões de carreira que querem adicionar ligadura elástica de hemorroidas ao consultório para gerar receita ambulatorial recorrente."}],
    [("Como cirurgião geral pode captar pacientes de hérnia inguinal que estão com dor há anos mas que têm medo de operar?", "Paciente com hérnia inguinal diagnosticada há 2 a 3 anos que ainda não operou tem medo de 3 coisas: medo da cirurgia em si ('e se der alguma complicação?'), medo do tempo de recuperação ('tenho reuniões importantes e não posso ficar 2 semanas afastado'), e medo da dor ('ouvi que a recuperação de hérnia é muito dolorosa'). Cirurgião geral que quer captar esse paciente: conteúdo no Instagram sobre 'hérnia inguinal laparoscópica — o que o paciente não te disse sobre a recuperação (spoiler: voltei a trabalhar em 5 dias)', vídeo sobre 'o que acontece se você não operar a hérnia — quando a hérnia vira emergência e por que é mais difícil de tratar', e FAQ de cirurgia de hérnia laparoscópica no site ('quanto tempo de internação? Quando posso voltar ao trabalho? Posso fazer atividade física?'). Paciente que lê e vê que 'cirurgião laparoscópico X faz em regime ambulatorial com alta em 4 horas e retorno ao trabalho em 5 dias' remove o obstáculo de recuperação e marca a consulta."),
     ("Como cirurgião geral pode usar a proctologia para criar receita de consultório independente de plano de saúde?", "Hemorroidas afetam 35 a 40% da população adulta, com pico entre 40 e 65 anos, e têm alta estigmatização (paciente evita buscar tratamento por vergonha ou por medo da cirurgia). Cirurgião que tem ligadura elástica no consultório — equipamento de R$3.000 a R$5.000, procedimento de 5 minutos sem anestesia com mínima dor — tem produto de entrada de baixo custo para o paciente (R$400 a R$800 vs. R$3.000 a R$8.000 da cirurgia convencional) e de alta margem para o cirurgião (custo direto do procedimento de R$30 a R$60). 5 ligaduras elásticas por semana = R$2.000 a R$4.000/semana de receita de consultório — independente de plano de saúde, sem internação, sem centro cirúrgico. Cirurgião que cria conteúdo desmistificador sobre hemorroidas — 'ligadura elástica para hemorroidas — como funciona, dói, e quando dá resultado' — tem captação orgânica de pacientes que passam anos com o problema por vergonha e que, ao descobrir que tem tratamento ambulatorial simples, marcam a consulta imediatamente."),
     ("Vale o cirurgião geral criar conteúdo sobre hérnia para pacientes que não sabem se precisam de cirurgia?", "Sim — paciente que sentiu um caroço na virilha ou no umbigo pesquisa 'como saber se é hérnia', 'hérnia precisa sempre de cirurgia', e 'quando a hérnia se torna perigosa'. Cirurgião que cria conteúdo: 'hérnia inguinal — como identificar, quando operar, e o que acontece se você deixar sem tratamento', 'hérnia umbilical vs. hérnia inguinal — a diferença no tratamento (e por que uma é mais urgente que a outra)', e 'hérnia encarceirada — quando é emergência e o que fazer se acontecer no fim de semana'. Conteúdo que responde as perguntas reais do paciente com hérnia — sem linguagem médica técnica — tem captação orgânica de adultos de 35 a 60 anos que identificaram o caroço e que querem entender se precisam operar antes de marcar consulta. Cirurgião com posicionamento de especialista em cirurgia de hérnia laparoscópica pelo conteúdo digital tem captação de pacientes que chegam à consulta já escolhendo o método e o cirurgião — sem precisar convencer.")],
    ["como-criar-infoproduto-sobre-marketing-para-profissionais-de-cirurgia-bariatrica",
     "como-criar-infoproduto-sobre-marketing-para-profissionais-de-gastroenterologia-clinica",
     "como-criar-infoproduto-sobre-marketing-para-profissionais-de-medicina-de-familia"])

